// src/EventContext.js

import React, { createContext, useContext, useState } from 'react';

const EventContext = createContext();

export const useEvents = () => useContext(EventContext);

export const EventProvider = ({ children }) => {
  const [events, setEvents] = useState([]);
  const [newEvent, setNewEvent] = useState({ event_name: '', event_state: 'draft', event_info: '' });
  const [selectedEventId, setSelectedEventId] = useState(null);
  const [selectedEvent, setSelectedEvent] = useState(null);

  return (
    <EventContext.Provider value={{ events, setEvents, newEvent, setNewEvent, selectedEventId, setSelectedEventId, selectedEvent, setSelectedEvent }}>
      {children}
    </EventContext.Provider>
  );
};
